using Compression.Registry;
using Reg = Compression.Registry.FormatRegistry;

namespace Compression.Lib;

/// <summary>
///   Identifies archive/compression formats by file extension and magic bytes.
///   Metadata is derived from the <see cref="FormatRegistry" /> at startup; only special
///   detection logic (PE/SFX scanning, LZMA heuristic, tar at offset 257) remains here.
/// </summary>
public static partial class FormatDetector {

  // Format enum is auto-generated by Compression.Registry.Generator
  // into FormatDetector.Format.g.cs — see SpecialFormats for Unknown/Sfx/Iso/Udf

  // ── Registry-backed lookup tables (built once on first use) ──────

  private static Dictionary<string, Format>? _idToFormat;
  private static Dictionary<Format, IFormatDescriptor>? _formatToDesc;
  private static Dictionary<string, Format>? _extToFormat; // single extensions
  private static Dictionary<string, Format>? _compoundExtToFormat; // compound extensions
  private static Dictionary<Format, Format>? _compoundToStream; // TarGz → Gzip
  private static Dictionary<Format, Format>? _streamToCompound; // Gzip → TarGz

  private static void EnsureRegistryMapped() {
    if (FormatDetector._idToFormat != null)
      return;

    FormatRegistration.EnsureInitialized();

    var idToFormat = new Dictionary<string, Format>(StringComparer.OrdinalIgnoreCase);
    var formatToDesc = new Dictionary<Format, IFormatDescriptor>();
    var extToFormat = new Dictionary<string, Format>(StringComparer.OrdinalIgnoreCase);
    var compoundExtToFormat = new Dictionary<string, Format>(StringComparer.OrdinalIgnoreCase);
    var compoundToStream = new Dictionary<Format, Format>();
    var streamToCompound = new Dictionary<Format, Format>();

    foreach (var desc in Reg.All) {
      if (!Enum.TryParse<Format>(desc.Id, out var f)) 
        continue;

      idToFormat[desc.Id] = f;
      formatToDesc[f] = desc;

      // Build extension → format maps
      foreach (var ext in desc.Extensions)
        extToFormat.TryAdd(ext.ToLowerInvariant(), f);

      foreach (var ext in desc.CompoundExtensions)
        compoundExtToFormat.TryAdd(ext.ToLowerInvariant(), f);

      // Build compound tar ↔ stream maps
      if (desc.TarCompressionFormatId != null && idToFormat.TryGetValue(desc.TarCompressionFormatId, out var streamF)) {
        compoundToStream[f] = streamF;
        streamToCompound[streamF] = f;
      }
    }

    // Second pass for compound tar mappings (stream format may have been registered after compound)
    foreach (var desc in Reg.All) {
      if (desc.TarCompressionFormatId == null) 
        continue;

      if (!idToFormat.TryGetValue(desc.Id, out var cf)) 
        continue;

      if (!idToFormat.TryGetValue(desc.TarCompressionFormatId, out var sf)) 
        continue;

      compoundToStream.TryAdd(cf, sf);
      streamToCompound.TryAdd(sf, cf);
    }

    FormatDetector._idToFormat = idToFormat;
    FormatDetector._formatToDesc = formatToDesc;
    FormatDetector._extToFormat = extToFormat;
    FormatDetector._compoundExtToFormat = compoundExtToFormat;
    FormatDetector._compoundToStream = compoundToStream;
    FormatDetector._streamToCompound = streamToCompound;
  }

  /// <summary>Get the descriptor for a format, or null if no descriptor exists (Sfx, Iso, Udf).</summary>
  private static IFormatDescriptor? GetDesc(Format f) {
    EnsureRegistryMapped();
    return FormatDetector._formatToDesc!.GetValueOrDefault(f);
  }

  // ── Category queries (derived from descriptor metadata) ──────────

  public static bool IsArchive(Format f) {
    if (f == Format.Sfx) 
      return true;

    var desc = GetDesc(f);
    return desc?.Category is FormatCategory.Archive or FormatCategory.CompoundTar or FormatCategory.DetectionOnly;
  }

  public static bool IsStreamFormat(Format f) {
    var desc = GetDesc(f);
    return desc?.Category is FormatCategory.Stream or FormatCategory.Wrapper;
  }

  public static bool IsCompoundTar(Format f) {
    var desc = GetDesc(f);
    return desc?.Category is FormatCategory.CompoundTar;
  }

  /// <summary>Returns the stream compression format wrapping a compound tar, or null if not compound.</summary>
  public static Format? GetTarCompression(Format f) {
    EnsureRegistryMapped();
    return FormatDetector._compoundToStream!.TryGetValue(f, out var s) ? s : null;
  }

  /// <summary>Returns the compound tar format for a given stream compression, or null.</summary>
  public static Format? GetCompoundTar(Format compression) {
    EnsureRegistryMapped();
    return FormatDetector._streamToCompound!.TryGetValue(compression, out var c) ? c : null;
  }

  // ── Extension detection ──────────────────────────────────────────

  public static Format DetectByExtension(string path) {
    EnsureRegistryMapped();
    var lower = path.ToLowerInvariant();

    // Compound extensions first (longest match, e.g. .tar.gz before .gz)
    foreach (var (ext, f) in FormatDetector._compoundExtToFormat!)
      if (lower.EndsWith(ext))
        return f;

    // Special cases not handled by registry
    var singleExt = Path.GetExtension(lower);
    if (singleExt == ".exe") 
      return DetectInstaller(path);

    if (singleExt is ".ar" or ".a" or ".deb") 
      return DetectArOrDeb(lower);

    if (lower.EndsWith(".sz_") || lower.EndsWith("._")) 
      return Format.Szdd;

    // Single extension lookup from registry
    if (!string.IsNullOrEmpty(singleExt) && FormatDetector._extToFormat!.TryGetValue(singleExt, out var format))
      return format;

    return Format.Unknown;
  }

  private static Format DetectArOrDeb(string lower)
    => lower.EndsWith(".deb") ? Format.Deb : Format.Ar;

  private static Format DetectInstaller(string path) {
    try {
      using var fs = File.OpenRead(path);
      var buf = new byte[2];
      // Quick check: must be a PE (MZ header)
      if (fs.Read(buf, 0, 2) < 2 || buf[0] != 'M' || buf[1] != 'Z')
        return Format.Unknown;

      // Check for NSIS/InnoSetup signatures in tail
      if (fs.Length > 65536) {
        fs.Seek(-65536, SeekOrigin.End);
        var tail = new byte[65536];
        var bytesRead = fs.Read(tail, 0, tail.Length);
        var tailSpan = tail.AsSpan(0, bytesRead);
        if (ContainsBytes(tailSpan, "NullsoftInst"u8)) return Format.Nsis;
        if (ContainsBytes(tailSpan, "Inno Setup"u8)) return Format.InnoSetup;
      }

      // Check for our own SFX trailer (SFX! magic at end)
      if (fs.Length >= 12) {
        fs.Seek(-4, SeekOrigin.End);
        Span<byte> magic = stackalloc byte[4];
        fs.ReadExactly(magic);
        if (magic[0] == 'S' && magic[1] == 'F' && magic[2] == 'X' && magic[3] == '!')
          return Format.Sfx;
      }

      // Check for third-party SFX: scan PE overlay for embedded archive
      var sfxInfo = PeOverlay.DetectEmbeddedArchive(path);
      if (sfxInfo != null)
        return Format.Sfx;
    } catch {
      /* ignore detection failure */
    }

    return Format.Unknown;
  }

  private static bool ContainsBytes(ReadOnlySpan<byte> haystack, ReadOnlySpan<byte> needle)
    => haystack.IndexOf(needle) >= 0;

  // ── Magic byte detection ─────────────────────────────────────────
  // Most signatures come from the registry. A few formats need special
  // multi-offset or heuristic logic that can't be expressed as simple
  // byte patterns, so those are handled explicitly after the registry scan.

  public static Format DetectByMagic(ReadOnlySpan<byte> header) {
    if (header.Length < 4) return Format.Unknown;

    EnsureRegistryMapped();

    // First try all registry-defined magic signatures
    foreach (var desc in Reg.All) {
      if (!FormatDetector._idToFormat!.TryGetValue(desc.Id, out var f)) 
        continue;

      foreach (var sig in desc.MagicSignatures)
        if (MatchesMagic(header, sig))
          return f;
    }

    // ── Special heuristic detections not expressible as simple magic ──

    // RefPack/QFS: 0x10 0xFB or at offset 4 (with compressed size prefix)
    if (header.Length >= 5 && (header[0] & 0xFE) == 0x10 && header[1] == 0xFB)
      return Format.RefPack;
    if (header.Length >= 9 && (header[4] & 0xFE) == 0x10 && header[5] == 0xFB)
      return Format.RefPack;

    // LZMA: byte 0 = properties (typically 0x5D), then 4-byte dict size LE
    if (header.Length >= 13 && header[0] < 0xE1 && header[0] % 9 < 9) {
      var dictSize = (uint)(header[1] | (header[2] << 8) | (header[3] << 16) | (header[4] << 24));
      if (dictSize > 0 && dictSize <= 0x40000000)
        return Format.Lzma;
    }

    // TAR: "ustar" at offset 257
    if (header.Length >= 263
      && header[257] == 'u'
      && header[258] == 's'
      && header[259] == 't'
      && header[260] == 'a'
      && header[261] == 'r')
      return Format.Tar;

    return Format.Unknown;
  }

  private static bool MatchesMagic(ReadOnlySpan<byte> header, MagicSignature sig) {
    if (header.Length < sig.Offset + sig.Bytes.Length) return false;

    var slice = header.Slice(sig.Offset, sig.Bytes.Length);
    if (sig.Mask != null) {
      for (var i = 0; i < sig.Bytes.Length; i++)
        if ((slice[i] & sig.Mask[i]) != (sig.Bytes[i] & sig.Mask[i]))
          return false;

      return true;
    }

    return slice.SequenceEqual(sig.Bytes);
  }

  // ── Full detection (extension + magic fallback) ──────────────────

  public static Format Detect(string path) {
    var byExt = DetectByExtension(path);
    if (byExt != Format.Unknown) return byExt;

    if (!File.Exists(path)) return Format.Unknown;

    var header = new byte[512];
    using var fs = File.OpenRead(path);
    var read = fs.Read(header, 0, header.Length);
    return DetectByMagic(header.AsSpan(0, read));
  }

  /// <summary>
  ///   For SFX files, returns the embedded archive's format and offset.
  ///   Handles both our own SFX format (SFX! trailer) and third-party SFX (PE overlay scan).
  ///   Returns null if the file is not an SFX or contains no detectable archive.
  /// </summary>
  public static (Format ArchiveFormat, long Offset, long Length)? GetSfxArchiveInfo(string path) {
    // First check our own SFX trailer
    var ownSfx = SfxBuilder.ReadTrailer(path);
    if (ownSfx != null)
      return (ownSfx.Value.Format, ownSfx.Value.Offset, ownSfx.Value.Length);

    // Then check for third-party SFX via PE overlay
    var peInfo = PeOverlay.DetectEmbeddedArchive(path);
    if (peInfo != null) {
      var fileLen = new FileInfo(path).Length;
      return (peInfo.Value.Format, peInfo.Value.Offset, fileLen - peInfo.Value.Offset);
    }

    return null;
  }

  // ── Default extension (derived from registry) ────────────────────

  public static string GetDefaultExtension(Format format) {
    var desc = GetDesc(format);
    if (desc != null) return desc.DefaultExtension;

    return format switch {
      Format.Sfx => ".exe",
      Format.Iso => ".iso",
      Format.Udf => ".udf",
      _ => ""
    };
  }

  // ── Extension set for stream formats (used by StripCompressionExtension) ──

  public static bool IsStreamExtension(string ext) {
    EnsureRegistryMapped();
    if (string.IsNullOrEmpty(ext)) return false;

    // Check single extensions of all stream/wrapper formats
    foreach (var desc in Reg.All) {
      if (desc.Category is not (FormatCategory.Stream or FormatCategory.Wrapper)) continue;

      foreach (var e in desc.Extensions)
        if (e.Equals(ext, StringComparison.OrdinalIgnoreCase))
          return true;
    }

    return false;
  }
}
